  ('f29a56e4-fa2d-5610-bb91-c714cd019a29'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escuchas a un amigo lamentarse. Elige la respuesta natural.', '{"options": ["I know, but it''s too late to change that now.", "Great, when does the scholarship start?", "Don''t worry, you can still apply tomorrow."], "say": "I wish I had applied for that scholarship when I had the chance.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/f29a56e4-fa2d-5610-bb91-c714cd019a29.mp3"}'::jsonb, '{"value": "I know, but it''s too late to change that now."}'::jsonb, 0.72, ARRAY['unidad22', 'reconocer_un_arrepentimi', 'listening', 'lsbal']),
  ('5b7c9faf-4d5e-58c5-80ef-7a7b5ce60187'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Tu acompañante dice esto en el coche. Elige la respuesta natural.', '{"options": ["I know, but there''s nothing we can do about it now.", "Yes, let''s leave earlier next time we meet.", "Great, so we won''t be late then."], "say": "If only we had left earlier, we wouldn''t be stuck in this traffic.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/5b7c9faf-4d5e-58c5-80ef-7a7b5ce60187.mp3"}'::jsonb, '{"value": "I know, but there''s nothing we can do about it now."}'::jsonb, 0.72, ARRAY['unidad22', 'interpretar_if_only_cond', 'listening', 'lsbal']),
  ('7deae9c7-cae5-5e23-8b72-60d13123e866'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'speaking'::skill, 'speaking_read_aloud'::content_item_type, 'Lee en voz alta:', '{"text": "If I had taken that job in Bogotá, I''d probably be earning more, but I would have missed seeing my kids grow up.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/7deae9c7-cae5-5e23-8b72-60d13123e866.mp3"}'::jsonb, '{"expected": "If I had taken that job in Bogotá, I''d probably be earning more, but I would have missed seeing my kids grow up."}'::jsonb, 0.72, ARRAY['unidad22', 'condicional_mixto_que_so', 'speaking', 'lsbal']),
  ('35c8ccbd-ec2a-5a7d-8f96-0f6befb19c23'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'speaking'::skill, 'speaking_read_aloud'::content_item_type, 'Lee en voz alta:', '{"text": "Honestly, if only I had listened to my dad''s advice, I wouldn''t have lost so much money on that deal.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/35c8ccbd-ec2a-5a7d-8f96-0f6befb19c23.mp3"}'::jsonb, '{"expected": "Honestly, if only I had listened to my dad''s advice, I wouldn''t have lost so much money on that deal."}'::jsonb, 0.72, ARRAY['unidad22', 'arrepentimiento_real_con', 'speaking', 'lsbal']),
  ('3c30828c-9309-556f-8973-6276e7c4cfa0'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'reading'::skill, 'multiple_choice'::content_item_type, 'Tu amiga rechazó una oferta y ahora se lamenta. Elige la frase que expresa ese reproche sobre el pasado: "I turned it down. ___"', '{"options": ["I should have accepted it.", "I must accept it.", "I had to accept it."]}'::jsonb, '{"value": "I should have accepted it."}'::jsonb, 0.72, ARRAY['unidad22', 'should_have_shouldn_t_ha', 'reading', 'eficgap']),
  ('9d17f834-2961-5ded-b71a-cb3206d600ef'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'writing'::skill, 'cloze'::content_item_type, 'Completa con el modal perfecto de deduccion sobre el pasado: "The lights are off and the car''s gone, so they ___ have left already."', '{"text": "Completa con el modal perfecto de deduccion sobre el pasado: \"The lights are off and the car''s gone, so they ___ have left already.\"", "options": ["must", "should", "would"]}'::jsonb, '{"value": "must"}'::jsonb, 0.72, ARRAY['unidad22', 'must_have_might_have_par', 'writing', 'eficgap']),
  ('b7513158-141d-5abe-b28d-1c5506ee48c7'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha y elige exactamente la frase que oíste.', '{"options": ["The neighbour whose Wi-Fi we borrowed during the blackout left this morning.", "The neighbour who borrowed our Wi-Fi during the blackout left this morning.", "The neighbour whose Wi-Fi we fixed after the blackout arrived this morning."], "say": "The neighbour whose Wi-Fi we borrowed during the blackout left this morning.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/b7513158-141d-5abe-b28d-1c5506ee48c7.mp3"}'::jsonb, '{"value": "The neighbour whose Wi-Fi we borrowed during the blackout left this morning."}'::jsonb, 0.72, ARRAY['unidad23', 'relativa_especificativa_', 'listening', 'lsbal']),
  ('a8a292d3-7e92-5a64-97b0-cb1d58d5ada5'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha y elige exactamente la frase que oíste.', '{"options": ["The little shop where my mum used to buy fabric is closing down next month.", "The little shop which my mum used to sell fabric is opening up next month.", "The little shop where my aunt used to buy fabric is closing down this month."], "say": "The little shop where my mum used to buy fabric is closing down next month.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/a8a292d3-7e92-5a64-97b0-cb1d58d5ada5.mp3"}'::jsonb, '{"value": "The little shop where my mum used to buy fabric is closing down next month."}'::jsonb, 0.72, ARRAY['unidad23', 'relativa_especificativa_', 'listening', 'lsbal']),
  ('5b3372e0-6bfa-5a9a-86dd-c3b583319b6d'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha la pregunta y elige la única respuesta natural.', '{"options": ["It was Marcela, the one who covered for me all week.", "Yes, the account is in Bogotá near the office.", "No, I haven''t been away from the office."], "say": "Who''s the colleague that handled the Bogotá account while you were away?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/5b3372e0-6bfa-5a9a-86dd-c3b583319b6d.mp3"}'::jsonb, '{"value": "It was Marcela, the one who covered for me all week."}'::jsonb, 0.72, ARRAY['unidad23', 'responder_con_the_one_wh', 'listening', 'lsbal']),
  ('22c05585-af71-5c57-a648-01fea91ce10a'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha la pregunta y elige la única respuesta natural.', '{"options": ["It''s mine, actually — the one I bought last year.", "Yes, I borrow the laptop from you sometimes.", "No, the work belongs to the laptop I use."], "say": "Is that the laptop you borrowed from work, or one that belongs to you?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/22c05585-af71-5c57-a648-01fea91ce10a.mp3"}'::jsonb, '{"value": "It''s mine, actually — the one I bought last year."}'::jsonb, 0.72, ARRAY['unidad23', 'relativa_de_objeto_omiti', 'listening', 'lsbal']),
  ('efe919ee-7b10-572c-8431-a548e3694b01'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'speaking'::skill, 'speaking_read_aloud'::content_item_type, 'Lee en voz alta:', '{"text": "Lima, which I''d never visited before, turned out to be the highlight of the whole trip.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/efe919ee-7b10-572c-8431-a548e3694b01.mp3"}'::jsonb, '{"expected": "Lima, which I''d never visited before, turned out to be the highlight of the whole trip."}'::jsonb, 0.72, ARRAY['unidad23', 'relativa_explicativa_non', 'speaking', 'lsbal']),
  ('04cd9685-de5e-50c8-8464-ae6b7cee1208'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'speaking'::skill, 'speaking_read_aloud'::content_item_type, 'Lee en voz alta:', '{"text": "The friend I trust the most is the one who tells me when I''m wrong.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/04cd9685-de5e-50c8-8464-ae6b7cee1208.mp3"}'::jsonb, '{"expected": "The friend I trust the most is the one who tells me when I''m wrong."}'::jsonb, 0.72, ARRAY['unidad23', 'relativa_de_objeto_omiti', 'speaking', 'lsbal']),
  ('ccf4b370-1555-5fe8-a0f3-d3b89add0907'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'reading'::skill, 'multiple_choice'::content_item_type, 'Una sola frase está bien puntuada. La información sobre Diego es solo un dato extra (explicativa). Elige la correcta.', '{"options": ["Diego, who runs the bakery downstairs, always saves me a loaf.", "Diego who runs the bakery downstairs, always saves me a loaf.", "Diego, that runs the bakery downstairs always saves me a loaf."]}'::jsonb, '{"value": "Diego, who runs the bakery downstairs, always saves me a loaf."}'::jsonb, 0.72, ARRAY['unidad23', 'explicativa_entre_comas_', 'reading', 'eficgap']),
  ('f186f100-203d-5953-936f-007da9269d50'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'writing'::skill, 'cloze'::content_item_type, 'Completa con UNA palabra. La explicativa va sobre una cosa, así que no puede ser ''that'': "My old phone, ___ still works fine, costs almost nothing to repair."', '{"text": "Completa con UNA palabra. La explicativa va sobre una cosa, así que no puede ser ''that'': \"My old phone, ___ still works fine, costs almost nothing to repair.\"", "options": ["which", "that", "who"]}'::jsonb, '{"value": "which"}'::jsonb, 0.72, ARRAY['unidad23', 'non_defining_con_which_p', 'writing', 'eficgap']),
  ('d2b56db5-f791-5c07-8994-3b77fdde469a'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha y elige exactamente lo que oíste.', '{"options": ["The lights were off and the car was gone, so they must have left for the weekend.", "The lights were on and the car was there, so they can''t have left for the weekend.", "The lights were off and the car was gone, so they might have stayed for the weekend."], "say": "The lights were off and the car was gone, so they must have left for the weekend.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/d2b56db5-f791-5c07-8994-3b77fdde469a.mp3"}'::jsonb, '{"value": "The lights were off and the car was gone, so they must have left for the weekend."}'::jsonb, 0.72, ARRAY['unidad24', 'deducci_n_sobre_el_pasad', 'listening', 'lsbal']),
  ('312684a1-f2cf-5347-b7de-c604776b8f8f'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha y elige exactamente lo que oíste.', '{"options": ["You needn''t have brought a gift; honestly, your being here is more than enough.", "You shouldn''t have brought a gift; honestly, your being here isn''t enough.", "You needn''t have bought a gift; frankly, your being here is more than enough."], "say": "You needn''t have brought a gift; honestly, your being here is more than enough.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/312684a1-f2cf-5347-b7de-c604776b8f8f.mp3"}'::jsonb, '{"value": "You needn''t have brought a gift; honestly, your being here is more than enough."}'::jsonb, 0.72, ARRAY['unidad24', 'esfuerzo_innecesario_en_', 'listening', 'lsbal']),
  ('fa38fbaf-03e0-55dd-8774-1c37a9ba955c'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'listening'::skill, 'listening'::content_item_type, 'Escucha la pregunta y elige la única respuesta lógica.', '{"options": ["She must have lost her phone, then; she always answers within minutes.", "She must have replied tomorrow once she sees them.", "She can''t have left already, so she answered everyone."], "say": "How come Marta didn''t reply to any of our messages all weekend?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/fa38fbaf-03e0-55dd-8774-1c37a9ba955c.mp3"}'::jsonb, '{"value": "She must have lost her phone, then; she always answers within minutes."}'::jsonb, 0.72, ARRAY['unidad24', 'responder_con_una_deducc', 'listening', 'lsbal']),
