  ('ccc187d4-6078-5bf3-9cc9-36ab8aac7d84'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'speaking'::skill, 'speaking_read_aloud'::content_item_type, 'Lee en voz alta:', '{"text": "Nobody answered the door, and the curtains were drawn, so they must have already gone on holiday.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/ccc187d4-6078-5bf3-9cc9-36ab8aac7d84.mp3"}'::jsonb, '{"expected": "Nobody answered the door, and the curtains were drawn, so they must have already gone on holiday."}'::jsonb, 0.72, ARRAY['unidad24', 'deducci_n_sobre_el_pasad', 'speaking', 'lsbal']),
  ('ffa0a2a7-67f2-5520-82ee-5bd1c9e4e292'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'speaking'::skill, 'speaking_read_aloud'::content_item_type, 'Lee en voz alta:', '{"text": "In my opinion, he should have admitted the mistake sooner; however, I can see why he hesitated.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/ffa0a2a7-67f2-5520-82ee-5bd1c9e4e292.mp3"}'::jsonb, '{"expected": "In my opinion, he should have admitted the mistake sooner; however, I can see why he hesitated."}'::jsonb, 0.72, ARRAY['unidad24', 'argumentar_y_matizar_sho', 'speaking', 'lsbal']),
  ('d2454bd2-bb6d-5d92-9b25-de2ae0c0c103'::uuid, '20000000-0000-0000-0000-000000000001'::uuid, 'B2'::cefr_level, 'reading'::skill, 'multiple_choice'::content_item_type, 'Deducción de una acción en curso en el pasado. Elige la opción correcta: "Her eyes were red and her voice was shaky — she ___ crying just before the meeting."', '{"options": ["must have been", "must have", "should have been"]}'::jsonb, '{"value": "must have been"}'::jsonb, 0.72, ARRAY['unidad24', 'deducci_n_del_pasado_en_', 'reading', 'eficgap'])
